    }

    boolean isBalanced() {
        pruneShadow();
        return shadow.isEmpty();
    }

    void close() {
        TimelineFrame frame = current.getAndSet(null);
        if (frame != null) {
            shadow.add(frame);
            frame.cool();
        }
